import { Component, OnInit, HostListener, ElementRef } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { ToastrService } from 'ngx-toastr';
import { newOrderService } from '../../services/newOrder/newOrder.service';
import { CustomerService } from '../../services/customer/customer.service';

@Component({
  selector: 'app-pos',
  templateUrl: './pos.component.html',
  styleUrl: './pos.component.css'
})
export class PosComponent implements OnInit {
  catalogItems: any[] = [];
  filteredCatalog: any[] = [];
  searchCatalogTerm: string = '';
  
  cartItems: any[] = [];
  checkoutForm!: FormGroup;
  submit: boolean = false;
  loading: boolean = false;
  
  suggestions: any[] = [];
  showSuggestions: boolean = false;
  activeField: 'name' | 'mobile' | null = null;
  customerId: string | null = null;
  
  workflows: any[] = [];
  firstWorkflowStatus: string = 'washing';

  constructor(
    private fb: FormBuilder,
    private newOrderService: newOrderService,
    private customerService: CustomerService,
    private router: Router,
    private toaster: ToastrService,
    private eRef: ElementRef
  ) { }

  ngOnInit(): void {
    const todayStr = new Date().toISOString().split('T')[0];
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    const tomorrowStr = tomorrow.toISOString().split('T')[0];

    this.checkoutForm = this.fb.group({
      date: [todayStr, Validators.required],
      dueDate: [tomorrowStr, Validators.required],
      name: ['', Validators.required],
      mobile: ['', Validators.required],
      whatsapp: [''],
      sameAsPhone: [false],
      address: ['', Validators.required],
      specialInstructions: [''],
      paymentMethod: ['cash']
    });

    // Subscriptions
    this.checkoutForm.get('mobile')?.valueChanges.subscribe(val => {
      if (this.checkoutForm.get('sameAsPhone')?.value) {
        this.checkoutForm.get('whatsapp')?.setValue(val, { emitEvent: false });
      }
    });

    this.checkoutForm.get('sameAsPhone')?.valueChanges.subscribe(checked => {
      if (checked) {
        const phone = this.checkoutForm.get('mobile')?.value;
        this.checkoutForm.get('whatsapp')?.setValue(phone, { emitEvent: false });
        this.checkoutForm.get('whatsapp')?.disable();
      } else {
        this.checkoutForm.get('whatsapp')?.enable();
      }
    });

    this.checkoutForm.get('name')?.valueChanges.subscribe(val => {
      if (this.checkoutForm.get('name')?.dirty && val && val.length >= 2) {
        this.fetchSuggestions(val, 'name');
      } else {
        if (this.activeField === 'name') this.showSuggestions = false;
      }
    });

    this.checkoutForm.get('mobile')?.valueChanges.subscribe(val => {
      if (this.checkoutForm.get('mobile')?.dirty && val && val.length >= 2) {
        this.fetchSuggestions(val, 'mobile');
      } else {
        if (this.activeField === 'mobile') this.showSuggestions = false;
      }
    });

    // Load Catalog Items
    this.loadCatalog();

    // Load Workflows
    const workflowStr = localStorage.getItem('workflow');
    if (workflowStr && workflowStr !== 'undefined') {
      try {
        this.workflows = JSON.parse(workflowStr);
        const firstWf = this.workflows.find((w: any) => w.order === 0);
        if (firstWf) {
          this.firstWorkflowStatus = firstWf.indentifier;
        }
      } catch (e) {
        console.error('Error parsing workflows', e);
      }
    }
  }

  loadCatalog() {
    this.newOrderService.getAllItems().subscribe({
      next: (res) => {
        this.catalogItems = res.data || [];
        this.filteredCatalog = [...this.catalogItems];
      },
      error: (err) => {
        this.toaster.error('Failed to load items catalog');
      }
    });
  }

  filterCatalog() {
    if (!this.searchCatalogTerm.trim()) {
      this.filteredCatalog = [...this.catalogItems];
    } else {
      const term = this.searchCatalogTerm.toLowerCase().trim();
      this.filteredCatalog = this.catalogItems.filter(item => 
        item.name.toLowerCase().includes(term)
      );
    }
  }

  // Cart Operations
  addToCart(item: any) {
    const existingIndex = this.cartItems.findIndex(cartItem => cartItem.id === item._id);
    if (existingIndex !== -1) {
      this.cartItems[existingIndex].qty += 1;
    } else {
      this.cartItems.push({
        id: item._id,
        name: item.name,
        qty: 1,
        amount: item.price
      });
    }
    this.toaster.success(`${item.name} added to cart`, '', { timeOut: 1000 });
  }

  incrementQty(index: number) {
    this.cartItems[index].qty += 1;
  }

  decrementQty(index: number) {
    if (this.cartItems[index].qty > 1) {
      this.cartItems[index].qty -= 1;
    } else {
      this.removeItem(index);
    }
  }

  removeItem(index: number) {
    this.cartItems.splice(index, 1);
  }

  getCartTotal(): number {
    return this.cartItems.reduce((sum, item) => sum + (item.qty * item.amount), 0);
  }

  clearCart() {
    this.cartItems = [];
  }

  // Customer Autocomplete Suggestions
  fetchSuggestions(term: string, field: 'name' | 'mobile') {
    this.activeField = field;
    this.customerService.getAll(term).subscribe({
      next: (res) => {
        if (res && res.data) {
          this.suggestions = res.data;
          this.showSuggestions = this.suggestions.length > 0;
        } else {
          this.suggestions = [];
          this.showSuggestions = false;
        }
      },
      error: () => {
        this.suggestions = [];
        this.showSuggestions = false;
      }
    });
  }

  selectCustomer(cust: any) {
    this.customerId = cust._id;
    this.checkoutForm.patchValue({
      name: cust.name,
      mobile: cust.mobile,
      whatsapp: cust.whatsapp || '',
      address: cust.address || '',
      sameAsPhone: cust.mobile && cust.whatsapp && cust.mobile === cust.whatsapp
    });
    if (cust.mobile && cust.whatsapp && cust.mobile === cust.whatsapp) {
      this.checkoutForm.get('whatsapp')?.disable();
    } else {
      this.checkoutForm.get('whatsapp')?.enable();
    }
    this.showSuggestions = false;
    this.suggestions = [];
    this.activeField = null;
  }

  @HostListener('document:click', ['$event'])
  clickout(event: any) {
    if (!this.eRef.nativeElement.contains(event.target)) {
      this.showSuggestions = false;
    }
  }

  get form() {
    return this.checkoutForm?.controls;
  }

  // Checkout Handler
  checkout(holdDraft: boolean) {
    this.submit = true;
    if (this.checkoutForm.invalid) {
      this.toaster.error('Please enter all required customer information');
      return;
    }
    if (this.cartItems.length === 0) {
      this.toaster.error('Your shopping cart is empty');
      return;
    }

    this.loading = true;
    const formValue = this.checkoutForm.getRawValue();
    
    // Choose status based on button clicked
    const statusVal = holdDraft ? 'confirm' : this.firstWorkflowStatus;

    const orderPayload = {
      customerId: this.customerId,
      date: formValue.date,
      dueDate: formValue.dueDate,
      specialInstructions: formValue.specialInstructions || '',
      customerName: formValue.name,
      phoneNumber: formValue.mobile,
      whatsappNumber: formValue.whatsapp,
      address: formValue.address,
      status: statusVal,
      type: 'item',
      items: this.cartItems.map(item => ({
        _id: item.id,
        name: item.name,
        qty: item.qty,
        amount: item.amount
      })),
      total: this.getCartTotal()
    };

    this.newOrderService.newOrder(orderPayload).subscribe({
      next: (res) => {
        this.toaster.success(
          holdDraft ? 'Order successfully held in Drafts' : 'Payment confirmed successfully',
          'Checkout Success'
        );

        const createdOrder = res.data;

        // Reset state
        this.checkoutForm.patchValue({
          name: '',
          mobile: '',
          whatsapp: '',
          sameAsPhone: false,
          address: '',
          specialInstructions: '',
          paymentMethod: 'cash'
        });
        this.customerId = null;
        this.cartItems = [];
        this.submit = false;
        this.loading = false;

        // If paying directly, generate and download the invoice PDF
        if (!holdDraft && createdOrder) {
          this.downloadInvoice(createdOrder._id, createdOrder.customerId);
          this.router.navigate(['/orders']); // Go straight to Kanban Operations board
        } else {
          this.router.navigate(['/savepannel']); // Go straight to Save Panel
        }
      },
      error: (err) => {
        this.toaster.error(err?.error?.message || 'Checkout failed');
        this.loading = false;
      }
    });
  }

  downloadInvoice(orderId: string, customerId: string) {
    this.newOrderService.getBill({ orderId, customerId }).subscribe({
      next: (res) => {
        const blob = new Blob([res], { type: 'application/pdf' });
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `invoice-${orderId}.pdf`;
        a.click();
      },
      error: (err) => {
        console.error('Invoice download failed', err);
      }
    });
  }
}
